import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a safe buffer size
        int bufferSize = 10;

        // Ensure that user input does not exceed buffer size
        if (name.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Truncating...");
            name = name.substring(0, bufferSize);
        }

        char[] buffer = new char[bufferSize];

        // Copy user input into the buffer with bounds checking
        name.getChars(0, Math.min(name.length(), bufferSize), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
